#include<bits/stdc++.h>
using namespace std;
int a[3010],b[3010],f[3010][3010];
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&b[i]);
    }
    for(int i=1;i<=n;i++)
    {
        int max1=0;
        for(int j=1;j<=n;j++)
        {
            if(a[i]!=b[j])
            {
                f[i][j]=f[i-1][j];
            }
            else
            {
                f[i][j]=max1+1;
            }
            if(b[j]<a[i])
            {
                max1=max(max1,f[i][j]);
            }
        }
    }
    int ans=0;
    for(int i=1;i<=n;i++)
    {
        ans=max(ans,f[n][i]);
    }
    printf("%d",ans);
    return 0;
}
